import React, { useState, useEffect } from 'react';
import api from '../lib/api';

const Inventory = () => {
  const [devices, setDevices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingDevice, setEditingDevice] = useState(null);
  const [activeTab, setActiveTab] = useState('basic');
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');

  const [formData, setFormData] = useState({
    name: '',
    ip_address: '',
    device_type: 'Router',
    vendor: 'Mikrotik',
    location: '',
    description: '',
    ssh_user: '',
    ssh_password: '',
    ssh_port: 22,
    ssh_protocol: 'ssh',
    snmp_version: 'v2c',
    snmp_community: 'public',
    snmp_username: '',
    snmp_password: '',
    snmp_auth_protocol: 'SHA',
    snmp_priv_protocol: 'AES',
    backup_enabled: true,
    backup_schedule: 'daily',
    is_active: true
  });

  const deviceTypes = ['Router', 'Switch', 'Firewall', 'Server', 'OLT', 'BRAS', 'PPPoE Server'];
  const vendors = ['Mikrotik', 'Cisco', 'Huawei', 'Juniper', 'Ubiquiti', 'Fortinet', 'HP/Aruba', 'Dell', 'Outro'];
  const snmpVersions = ['v1', 'v2c', 'v3'];

  useEffect(() => {
    loadDevices();
  }, []);

  const loadDevices = async () => {
    setLoading(true);
    try {
      const response = await api.get('/devices/');
      setDevices(response.data.results || response.data || []);
    } catch (error) {
      console.error('Error loading devices:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Mapear campos para API
      const apiData = {
        name: formData.name,
        hostname: formData.name,
        ip: formData.ip_address,
        ip_address: formData.ip_address,
        device_type: formData.device_type,
        type: formData.device_type,
        vendor: formData.vendor,
        location: formData.location,
        description: formData.description,
        username: formData.ssh_user,
        ssh_user: formData.ssh_user,
        ssh_password: formData.ssh_password,
        ssh_port: formData.ssh_port,
        ssh_protocol: formData.ssh_protocol,
        snmp_version: formData.snmp_version,
        snmp_community: formData.snmp_community,
        snmp_username: formData.snmp_username,
        snmp_password: formData.snmp_password,
        snmp_auth_protocol: formData.snmp_auth_protocol,
        snmp_priv_protocol: formData.snmp_priv_protocol,
        backup_enabled: formData.backup_enabled,
        backup_schedule: formData.backup_schedule,
        is_active: formData.is_active
      };

      if (editingDevice) {
        await api.patch(`/devices/${editingDevice.id}/`, apiData);
      } else {
        await api.post('/devices/', apiData);
      }

      loadDevices();
      resetForm();
    } catch (error) {
      console.error('Error saving device:', error);
      alert('Erro ao salvar dispositivo: ' + (error.response?.data?.detail || error.message));
    }
  };

  const handleEdit = (device) => {
    setFormData({
      name: device.name || device.hostname || '',
      ip_address: device.ip_address || device.ip || '',
      device_type: device.device_type || device.type || 'Router',
      vendor: device.vendor || 'Mikrotik',
      location: device.location || '',
      description: device.description || '',
      ssh_user: device.ssh_user || device.username || '',
      ssh_password: '',
      ssh_port: device.ssh_port || 22,
      ssh_protocol: device.ssh_protocol || 'ssh',
      snmp_version: device.snmp_version || 'v2c',
      snmp_community: device.snmp_community || 'public',
      snmp_username: device.snmp_username || '',
      snmp_password: '',
      snmp_auth_protocol: device.snmp_auth_protocol || 'SHA',
      snmp_priv_protocol: device.snmp_priv_protocol || 'AES',
      backup_enabled: device.backup_enabled !== false,
      backup_schedule: device.backup_schedule || 'daily',
      is_active: device.is_active !== false
    });
    setEditingDevice(device);
    setShowForm(true);
    setActiveTab('basic');
  };

  const handleDelete = async (device) => {
    if (!window.confirm(`Excluir dispositivo "${device.name || device.hostname}"?`)) return;

    try {
      await api.delete(`/devices/${device.id}/`);
      loadDevices();
    } catch (error) {
      console.error('Error deleting device:', error);
    }
  };

  const resetForm = () => {
    setFormData({
      name: '',
      ip_address: '',
      device_type: 'Router',
      vendor: 'Mikrotik',
      location: '',
      description: '',
      ssh_user: '',
      ssh_password: '',
      ssh_port: 22,
      ssh_protocol: 'ssh',
      snmp_version: 'v2c',
      snmp_community: 'public',
      snmp_username: '',
      snmp_password: '',
      snmp_auth_protocol: 'SHA',
      snmp_priv_protocol: 'AES',
      backup_enabled: true,
      backup_schedule: 'daily',
      is_active: true
    });
    setEditingDevice(null);
    setShowForm(false);
    setActiveTab('basic');
  };

  const filteredDevices = devices.filter(device => {
    const matchesSearch = (device.name || device.hostname || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
                         (device.ip_address || device.ip || '').includes(searchTerm);
    const matchesType = filterType === 'all' || (device.device_type || device.type) === filterType;
    return matchesSearch && matchesType;
  });

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold text-white">Inventário de Dispositivos</h2>
          <p className="text-gray-400 text-sm">{devices.length} dispositivos cadastrados</p>
        </div>
        <button
          onClick={() => setShowForm(true)}
          className="px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition flex items-center space-x-2"
        >
          <span>➕</span>
          <span>Novo Dispositivo</span>
        </button>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-4">
        <input
          type="text"
          placeholder="🔍 Buscar por nome ou IP..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="flex-1 min-w-64 bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <select
          value={filterType}
          onChange={(e) => setFilterType(e.target.value)}
          className="bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option value="all">Todos os tipos</option>
          {deviceTypes.map(type => (
            <option key={type} value={type}>{type}</option>
          ))}
        </select>
      </div>

      {/* Device Form */}
      {showForm && (
        <div className="bg-gray-800 rounded-lg border border-gray-700 overflow-hidden">
          <div className="flex items-center justify-between p-4 border-b border-gray-700">
            <h3 className="text-lg font-medium text-white">
              {editingDevice ? 'Editar Dispositivo' : 'Novo Dispositivo'}
            </h3>
            <button onClick={resetForm} className="text-gray-400 hover:text-white">✕</button>
          </div>

          {/* Tabs */}
          <div className="flex border-b border-gray-700">
            {[
              { id: 'basic', label: 'Básico' },
              { id: 'ssh', label: 'SSH' },
              { id: 'snmp', label: 'SNMP' },
              { id: 'backup', label: 'Backup' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`px-6 py-3 text-sm font-medium transition ${
                  activeTab === tab.id
                    ? 'text-blue-400 border-b-2 border-blue-400'
                    : 'text-gray-400 hover:text-white'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>

          <form onSubmit={handleSubmit} className="p-6">
            {/* Basic Tab */}
            {activeTab === 'basic' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Nome / Hostname *</label>
                  <input
                    type="text"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    required
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Endereço IP *</label>
                  <input
                    type="text"
                    value={formData.ip_address}
                    onChange={(e) => setFormData({ ...formData, ip_address: e.target.value })}
                    required
                    placeholder="192.168.1.1"
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Tipo de Dispositivo</label>
                  <select
                    value={formData.device_type}
                    onChange={(e) => setFormData({ ...formData, device_type: e.target.value })}
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    {deviceTypes.map(type => (
                      <option key={type} value={type}>{type}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Fabricante</label>
                  <select
                    value={formData.vendor}
                    onChange={(e) => setFormData({ ...formData, vendor: e.target.value })}
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    {vendors.map(v => (
                      <option key={v} value={v}>{v}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Localização</label>
                  <input
                    type="text"
                    value={formData.location}
                    onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                    placeholder="Datacenter, Sala X..."
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="flex items-center space-x-2 mt-6">
                    <input
                      type="checkbox"
                      checked={formData.is_active}
                      onChange={(e) => setFormData({ ...formData, is_active: e.target.checked })}
                      className="w-5 h-5 rounded bg-gray-700 border-gray-600 text-blue-600"
                    />
                    <span className="text-gray-300">Dispositivo Ativo</span>
                  </label>
                </div>
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-300 mb-1">Descrição</label>
                  <textarea
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    rows={2}
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              </div>
            )}

            {/* SSH Tab */}
            {activeTab === 'ssh' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Usuário SSH</label>
                  <input
                    type="text"
                    value={formData.ssh_user}
                    onChange={(e) => setFormData({ ...formData, ssh_user: e.target.value })}
                    placeholder="root"
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Senha SSH</label>
                  <input
                    type="password"
                    value={formData.ssh_password}
                    onChange={(e) => setFormData({ ...formData, ssh_password: e.target.value })}
                    placeholder="••••••••"
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Porta SSH</label>
                  <input
                    type="number"
                    value={formData.ssh_port}
                    onChange={(e) => setFormData({ ...formData, ssh_port: parseInt(e.target.value) })}
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1">Protocolo</label>
                  <select
                    value={formData.ssh_protocol}
                    onChange={(e) => setFormData({ ...formData, ssh_protocol: e.target.value })}
                    className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    <option value="ssh">SSH</option>
                    <option value="telnet">Telnet</option>
                  </select>
                </div>
              </div>
            )}

            {/* SNMP Tab */}
            {activeTab === 'snmp' && (
              <div className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Versão SNMP</label>
                    <select
                      value={formData.snmp_version}
                      onChange={(e) => setFormData({ ...formData, snmp_version: e.target.value })}
                      className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      {snmpVersions.map(v => (
                        <option key={v} value={v}>{v.toUpperCase()}</option>
                      ))}
                    </select>
                  </div>

                  {formData.snmp_version !== 'v3' && (
                    <div className="md:col-span-2">
                      <label className="block text-sm font-medium text-gray-300 mb-1">Community String</label>
                      <input
                        type="text"
                        value={formData.snmp_community}
                        onChange={(e) => setFormData({ ...formData, snmp_community: e.target.value })}
                        placeholder="public"
                        className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                      />
                    </div>
                  )}
                </div>

                {formData.snmp_version === 'v3' && (
                  <div className="bg-gray-700/50 rounded-lg p-4 space-y-4">
                    <h4 className="text-sm font-medium text-white">Configuração SNMPv3</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-medium text-gray-300 mb-1">Usuário SNMP</label>
                        <input
                          type="text"
                          value={formData.snmp_username}
                          onChange={(e) => setFormData({ ...formData, snmp_username: e.target.value })}
                          className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white"
                        />
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-300 mb-1">Senha de Autenticação</label>
                        <input
                          type="password"
                          value={formData.snmp_password}
                          onChange={(e) => setFormData({ ...formData, snmp_password: e.target.value })}
                          className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white"
                        />
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-300 mb-1">Protocolo de Autenticação</label>
                        <select
                          value={formData.snmp_auth_protocol}
                          onChange={(e) => setFormData({ ...formData, snmp_auth_protocol: e.target.value })}
                          className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white"
                        >
                          <option value="SHA">SHA</option>
                          <option value="MD5">MD5</option>
                        </select>
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-300 mb-1">Protocolo de Privacidade</label>
                        <select
                          value={formData.snmp_priv_protocol}
                          onChange={(e) => setFormData({ ...formData, snmp_priv_protocol: e.target.value })}
                          className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white"
                        >
                          <option value="AES">AES</option>
                          <option value="DES">DES</option>
                        </select>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Backup Tab */}
            {activeTab === 'backup' && (
              <div className="space-y-4">
                <label className="flex items-center space-x-2">
                  <input
                    type="checkbox"
                    checked={formData.backup_enabled}
                    onChange={(e) => setFormData({ ...formData, backup_enabled: e.target.checked })}
                    className="w-5 h-5 rounded bg-gray-700 border-gray-600 text-blue-600"
                  />
                  <span className="text-gray-300">Habilitar Backup Automático</span>
                </label>

                {formData.backup_enabled && (
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Agendamento</label>
                    <select
                      value={formData.backup_schedule}
                      onChange={(e) => setFormData({ ...formData, backup_schedule: e.target.value })}
                      className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      <option value="hourly">A cada hora</option>
                      <option value="daily">Diariamente</option>
                      <option value="weekly">Semanalmente</option>
                      <option value="monthly">Mensalmente</option>
                    </select>
                  </div>
                )}
              </div>
            )}

            {/* Form Actions */}
            <div className="flex justify-end space-x-3 mt-6 pt-6 border-t border-gray-700">
              <button
                type="button"
                onClick={resetForm}
                className="px-6 py-2 bg-gray-600 hover:bg-gray-500 text-white rounded-lg transition"
              >
                Cancelar
              </button>
              <button
                type="submit"
                className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition"
              >
                {editingDevice ? 'Atualizar' : 'Cadastrar'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Device List */}
      <div className="bg-gray-800 rounded-lg border border-gray-700 overflow-hidden">
        <table className="w-full">
          <thead className="bg-gray-700">
            <tr>
              <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Status</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Nome</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">IP</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Tipo</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Fabricante</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Localização</th>
              <th className="px-4 py-3 text-right text-sm font-medium text-gray-300">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-700">
            {filteredDevices.length === 0 ? (
              <tr>
                <td colSpan={7} className="px-4 py-8 text-center text-gray-400">
                  {searchTerm ? 'Nenhum dispositivo encontrado' : 'Nenhum dispositivo cadastrado'}
                </td>
              </tr>
            ) : (
              filteredDevices.map(device => (
                <tr key={device.id} className="hover:bg-gray-700/50 transition">
                  <td className="px-4 py-3">
                    <div className={`w-3 h-3 rounded-full ${device.is_active !== false ? 'bg-green-500' : 'bg-red-500'}`}></div>
                  </td>
                  <td className="px-4 py-3 text-white font-medium">{device.name || device.hostname || '-'}</td>
                  <td className="px-4 py-3 text-gray-300 font-mono text-sm">{device.ip_address || device.ip || '-'}</td>
                  <td className="px-4 py-3">
                    <span className="px-2 py-1 bg-blue-600/20 text-blue-400 rounded text-xs">
                      {device.device_type || device.type || 'N/A'}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-gray-300">{device.vendor || '-'}</td>
                  <td className="px-4 py-3 text-gray-400 text-sm">{device.location || '-'}</td>
                  <td className="px-4 py-3 text-right">
                    <button
                      onClick={() => handleEdit(device)}
                      className="text-blue-400 hover:text-blue-300 mr-3 text-sm"
                    >
                      Editar
                    </button>
                    <button
                      onClick={() => handleDelete(device)}
                      className="text-red-400 hover:text-red-300 text-sm"
                    >
                      Excluir
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Inventory;
